#!/usr/bin/env python3
import os,sys;
import subprocess as sp
try:
	args = 'pip install -r requirements.txt'

	sp.check_output(args)
except Exception as err :
	sys.stderr.write(f'Error in installing the dependencies. Error: {err}\n')
	raise


with open('version-build-number','w') as f : 
	if os.path.isfile('requirements.txt'):
		print(int(sp.check_output(args = 'head -1 requirements.txt').decode().split()[0].strip()),file=f)
	else:
		print(-999, file=f)